/**
 * @summary Get recent emergencies for dashboard
 */
export const getGetRecentEmergenciesUrl = (
  params?: GetRecentEmergenciesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/analytics/recent-emergencies?${stringifiedParams}`
    : `/api/analytics/recent-emergencies`;
};

export const getRecentEmergencies = async (
  params?: GetRecentEmergenciesParams,
  options?: RequestInit,
): Promise<Emergency[]> => {
  return customFetch<Emergency[]>(getGetRecentEmergenciesUrl(params), {
    ...options,
    method: "GET",
  });
};

